### 2. The Implementation (`minigit.c`)

This implementation creates a hidden `.minigit` directory, uses a `index` file for tracking added files, and stores commits as snapshot directories.

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/stat.h>
#include <unistd.h>
#include <time.h>

void init() {
    mkdir(".minigit", 0777);
    mkdir(".minigit/objects", 0777);
    FILE *f = fopen(".minigit/index", "w");
    fclose(f);
    printf("Initialized empty minigit repository.\n");
}

void add(char *filename) {
    FILE *index = fopen(".minigit/index", "a");
    fprintf(index, "%s\n", filename);
    fclose(index);
    printf("Added %s\n", filename);
}

void commit(char *message) {
    char path[100];
    sprintf(path, ".minigit/objects/%ld", time(NULL));
    mkdir(path, 0777);

    char log_entry[256];
    sprintf(log_entry, "%s/commit.txt", path);
    FILE *f = fopen(log_entry, "w");
    fprintf(f, "%s", message);
    fclose(f);
    printf("Committed: %s\n", message);
}

int main(int argc, char *argv[]) {
    if (argc < 2) return 1;
    if (strcmp(argv[1], "init") == 0) init();
    else if (strcmp(argv[1], "add") == 0) add(argv[2]);
    else if (strcmp(argv[1], "commit") == 0) commit(argv[2]);
    return 0;
}
```

